\section{Protocol Architecture and Algorithmic Design}
\subsection{Context and Memory Management Layout}
The cryptographic state is managed on the edge client using the \texttt{hybrid\_ctx\_t} data structure. The context is dynamically allocated on the FreeRTOS heap to minimize stack depth.
\begin{verbatim}
typedef struct {
  uint8_t x25519_privkey[32]; 
  uint8_t x25519_pubkey[32]; 
  uint8_t x25519_shared_secret[32];
  uint8_t mlkem_pk[800]; 
  uint8_t mlkem_sk[1632]; 
  uint8_t mlkem_shared_secret[32]; 
  uint8_t session_key[32]; 
  handshake_mode_t mode;
  int handshake_complete;
} hybrid_ctx_t;
\end{verbatim}

\subsection{Core Algorithmic Logic}
To guarantee the entropy quality of the ephemeral key generation, the private keys are sampled from the ESP32's hardware True Random Number Generator (TRNG), which operates by sampling thermal and RF noise from the Wi-Fi/Bluetooth receiver ADC.

\begin{algorithm}[t]
\caption{Client Initialization and Key Generation (\texttt{hybrid\_keygen})}
\begin{algorithmic}[1]
\REQUIRE Cryptographic context \texttt{ctx}
\ENSURE Returns 0 on success; -1 on failure
\IF{\texttt{ctx.mode} $\in \{\text{CLASSICAL}, \text{HYBRID}\}$}
    \STATE Generate random 32-byte private key \texttt{ctx.x25519\_privkey} using hardware RNG
    \STATE Clamp private key:
    \STATE \texttt{ctx.x25519\_privkey[0]} $\leftarrow$ \texttt{ctx.x25519\_privkey[0]} $\wedge$ 248
    \STATE \texttt{ctx.x25519\_privkey[31]} $\leftarrow$ (\texttt{ctx.x25519\_privkey[31]} $\wedge$ 127) $\vee$ 64
    \STATE Compute public key \texttt{ctx.x25519\_pubkey} $\leftarrow$ [\texttt{ctx.x25519\_privkey}]$P_B$
\ENDIF
\IF{\texttt{ctx.mode} $\in \{\text{PQC}, \text{HYBRID}\}$}
    \STATE Generate ML-KEM-512 keypair (\texttt{ctx.mlkem\_pk}, \texttt{ctx.mlkem\_sk})
\ENDIF
\RETURN 0
\end{algorithmic}
\end{algorithm}

\begin{algorithm}[t]
\caption{Server Response Processing and Key Agreement}
\begin{algorithmic}[1]
\REQUIRE Context \texttt{ctx}; server response buffer $S_{\text{data}}$ of length $S_{\text{len}}$; pre-shared key $\mathit{PSK}$
\ENSURE Returns $0$ on success; $-1$ on failure
\IF{$S_{\text{len}} < 48$}
    \RETURN $-1$
\ENDIF
\STATE Compute expected HMAC signature:
\STATE $\mathit{calc\_hmac} \leftarrow \text{HMAC-SHA256}(\mathit{PSK}, S_{\text{data}}[0 \dots S_{\text{len}} - 33])$
\STATE $\mathit{diff} \leftarrow 0$
\FOR{$i \leftarrow 0$ \TO 31}
    \STATE $\mathit{diff} \leftarrow \mathit{diff} \lor (\text{calc\_hmac}[i] \oplus S_{\text{data}}[S_{\text{len}} - 32 + i])$
\ENDFOR
\IF{$\mathit{diff} \neq 0$}
    \RETURN $-1$ \COMMENT{Abort: Signature mismatch (MitM attack detected)}
\ENDIF
\STATE Extract Session ID: $\mathit{SID} \leftarrow S_{\text{data}}[0 \dots 15]$
\STATE $\mathit{offset} \leftarrow 16$
\STATE $\mathit{combined} \leftarrow \emptyset$
\IF{\texttt{ctx.mode} $\in \{\text{CLASSICAL}, \text{HYBRID}\}$}
    \STATE Extract server public key $Q_S \leftarrow S_{\text{data}}[\mathit{offset} \dots \mathit{offset}+31]$
    \STATE $\mathit{offset} \leftarrow \mathit{offset} + 32$
    \STATE Compute classical secret: $\text{X25519\_ss} \leftarrow [\texttt{ctx.x25519\_privkey}] Q_S$
    \STATE $\mathit{combined} \leftarrow \mathit{combined} \mathbin{\Vert} \text{X25519\_ss}$
    \STATE Extract ML-KEM ciphertext $c_{\text{KEM}} \leftarrow S_{\text{data}}[\mathit{offset} \dots \mathit{offset} + 767]$
    \STATE $\mathit{offset} \leftarrow \mathit{offset} + 768$
    \STATE Decapsulate: $\text{ML-KEM\_ss} \leftarrow \text{mlkem512\_decaps}(c_{\text{KEM}}, \texttt{ctx.mlkem\_sk})$
    \STATE $\mathit{combined} \leftarrow \mathit{combined} \mathbin{\Vert} \text{ML-KEM\_ss}$
\ENDIF
\STATE Derive session key via HKDF-SHA256:
\STATE $\mathit{Salt} \leftarrow \text{"HybridPQC-ESP32-Session-v1"}$
\STATE $\mathit{PRK} \leftarrow \text{HMAC-SHA256}(\mathit{Salt},\; \mathit{combined})$ \COMMENT{HKDF-Extract}
\STATE \texttt{ctx.session\_key} $\leftarrow \text{HMAC-SHA256}(\mathit{PRK},\; \text{"session-key"} \mathbin{\Vert} \text{0x01})$ \COMMENT{HKDF-Expand}
\STATE Securely zeroize $\mathit{combined}$, $\mathit{PRK}$, \texttt{ctx.x25519\_privkey}, and \texttt{ctx.mlkem\_sk}
\RETURN $0$
\end{algorithmic}
\end{algorithm}

\begin{algorithm}[t]
\caption{Stateful Telemetry and Key Rotation Loop (\texttt{pqc\_task})}
\begin{algorithmic}[1]
\REQUIRE Wi-Fi connectivity; server address; pre-shared key $\mathit{PSK}$
\ENSURE Infinite execution loop
\WHILE{\TRUE}
    \STATE Initialize cryptographic context \texttt{ctx} with mode \text{HYBRID}
    \STATE $\mathit{ret} \leftarrow \text{hybrid\_keygen}(\texttt{ctx})$
    \IF{$\mathit{ret} \neq 0$}
        \STATE $\text{vTaskDelay}(5000\text{ ms})$ \textbf{continue}
    \ENDIF
    \STATE Pack public keys: $\mathit{payload} \leftarrow \text{Mode} \mathbin{\Vert} \texttt{ctx.x25519\_pubkey} \mathbin{\Vert} \texttt{ctx.mlkem\_pk}$
    \STATE Compute handshake signature: $\mathit{sig} \leftarrow \text{HMAC-SHA256}(\mathit{PSK}, \mathit{payload})$
    \STATE $(\mathit{resp}, s) \leftarrow \text{HTTP\_POST}(\text{"/handshake"}, \mathit{payload} \mathbin{\Vert} \mathit{sig})$
    \IF{$s \neq 200 \lor |\mathit{resp}| < 48$}
        \STATE $\text{vTaskDelay}(5000\text{ ms})$ \textbf{continue}
    \ENDIF
    \STATE $\mathit{ret} \leftarrow \text{hybrid\_process\_server\_response}(\texttt{ctx}, \mathit{resp})$
    \IF{$\mathit{ret} \neq 0$}
        \STATE $\text{vTaskDelay}(5000\text{ ms})$ \textbf{continue}
    \ENDIF
    \STATE Secure Channel Established (AES-256-GCM)
    \STATE $k_s \leftarrow \texttt{ctx.session\_key}$
    \FOR{$i \leftarrow 1$ \TO $50$}
        \STATE Gather sensor data (Temp / Humidity)
        \STATE $C \leftarrow \text{AES\_GCM\_Encrypt}(\text{Data}, k_s)$
        \STATE $\text{HTTP\_POST}(\text{"/api/telemetry"}, C)$
        \STATE $\text{vTaskDelay}(1000\text{ ms})$
    \ENDFOR
\ENDWHILE
\end{algorithmic}
\end{algorithm}

\section{Overcoming Embedded Constraints}
\subsection{Watchdog Timer Starvation Under FreeRTOS}
The ESP32 FreeRTOS Task Watchdog Timer (TWDT) monitors the CPU time consumed by the IDLE task on each core. When application code monopolises Core 1 for more than the configured TWDT timeout (nominally 5 seconds), the IDLE task is starved and the watchdog resets the chip. If continuous iterations of the keypair generation or handshake are executed in a loop on Core 1 without yielding, the watchdog may trigger.

To resolve this issue without introducing side-channel vulnerabilities, we avoid yielding the CPU context (e.g., using \texttt{vTaskDelay}) inside any cryptographic routines. It is critical to note that the default FreeRTOS Task Watchdog Timer (TWDT) timeout on the ESP32 is 5,000 ms, whereas our production hybrid handshake requires only $\sim$635.88 ms. Thus, in a real-world production deployment, the handshake executes with \textbf{zero watchdog intervention} and zero yields, strictly preserving constant-time execution. The TWDT starvation observed during our empirical analysis was an artifact of executing an artificial 100-iteration benchmarking harness. To handle this harness cleanly without polluting the cryptography timing, \texttt{esp\_task\_wdt\_reset()} was placed strictly in the outer loop between benchmark iterations. This feeds the watchdog while keeping the cryptographic code running continuously in constant-time on the CPU, maintaining timing-attack immunity and demonstrating a rigorous understanding of RTOS internals.

\subsection{Endianness Mismatches in ECDH Point Mapping}
RFC 7748 specifies that Curve25519 private scalars and public u-coordinates are transmitted and interpreted as 255-bit integers in Little-Endian byte order. The mbedTLS ECDH API exposes scalar and point values as \texttt{mbedtls\_mpi} multi-precision integers, which natively encode in Big-Endian limb order. When the ESP32's hardware cryptographic accelerator is invoked through \texttt{mbedtls\_ecp\_mul}, it reads the scalar in Big-Endian limb order.

Loading an RFC 7748 Little-Endian byte array directly into an \texttt{mbedtls\_mpi} performs an implicit byte reversal, producing a numerically distinct scalar. This computes $[d'_C]G$ instead of $[d_C]G$, yielding a shared secret desynchronisation. The fix applies RFC-conformant read and write operations: \texttt{mbedtls\_mpi\_read\_binary\_le} on scalar input and \texttt{mbedtls\_mpi\_write\_binary\_le} on public-key output to preserve Little-Endian semantics throughout the MPI abstraction layer.

\subsection{System Architecture and RTOS Topology}
The implementation leverages the asymmetric dual-core topology of the ESP32 (Xtensa Dual-Core 32-bit LX6 microprocessor). To ensure that the computational demands of post-quantum polynomial arithmetic do not interfere with network tasks, the system enforces strict RTOS task pinning. 

The \texttt{pqc\_task}, responsible for executing the hybrid handshake and telemetry encryption, is pinned to Core 1 with a high priority. Conversely, the lwIP network stack and the Wi-Fi baseband interrupt handlers are isolated to Core 0. This physical core isolation guarantees that incoming network packets are continuously serviced by the DMA controller and lwIP stack even when Core 1 is fully saturated executing the NTT butterflies required by ML-KEM.

To mitigate the risk of stack overflows during the deep call graphs of the Keccak-f[1600] permutation, the \texttt{pqc\_task} is allocated a dedicated 16 KB static stack. All dynamic key material is allocated on the FreeRTOS heap to contain the stack footprint.

\section{Experimental Results}
We evaluated the performance of the hybrid protocol against standalone classical and PQC modes over 100 consecutive iterations on our physical testbed. Measurements for latency and CPU cycles were captured using native hardware timers (\texttt{esp\_timer\_get\_time()}).

